// HMAC signature verification against VAPI_WEBHOOK_SECRET.
// Vapi sends the raw payload + header X-Vapi-Signature with hex HMAC-SHA256.
// Kept lenient in dev: if the env is the TODO placeholder we skip verification.
const crypto = require('crypto');
const headers = $input.item.json.headers || {};
const body = $input.item.json.body || $input.item.json || {};
const sig = headers['x-vapi-signature'] || headers['X-Vapi-Signature'] || '';
const secret = process.env.VAPI_WEBHOOK_SECRET || 'TODO_SET_VAPI_WEBHOOK_SECRET';

let ok = false;
if (secret === 'TODO_SET_VAPI_WEBHOOK_SECRET') {
  // Placeholder mode — accept so activation can smoke-test without secret wiring.
  ok = true;
} else if (sig) {
  const expected = crypto.createHmac('sha256', secret)
    .update(typeof body === 'string' ? body : JSON.stringify(body))
    .digest('hex');
  try {
    ok = crypto.timingSafeEqual(Buffer.from(expected, 'hex'), Buffer.from(String(sig), 'hex'));
  } catch (e) { ok = false; }
}

if (!ok) return { json: { _error: true, error: 'invalid signature' } };
return { json: Object.assign({}, body, { _verified: true }) };

// Extract the chunk fields from Vapi's payload shape.
// Expected keys: call.id, transcript.text, transcript.role,
// transcript.confidence, transcript.timestamp, metadata.client_id,
// metadata.agent_id, metadata.lead_id, metadata.chunk_sequence.
const src = $input.item.json || {};
const call = src.call || {};
const t = src.transcript || {};
const meta = src.metadata || {};
const speaker = (t.role === 'user' || t.role === 'customer') ? 'customer' : (t.role === 'assistant' || t.role === 'agent') ? 'agent' : 'unknown';
return { json: {
  call_id: call.id || src.call_id || null,
  client_id: meta.client_id || null,
  agent_id: meta.agent_id || null,
  lead_id: meta.lead_id || null,
  chunk_sequence: Number(meta.chunk_sequence || 0),
  speaker,
  transcript_text: t.text || '',
  transcript_confidence: t.confidence != null ? Number(t.confidence) : null,
  detected_at: t.timestamp || new Date().toISOString()
} };

const rpcResp = $input.item.json;
let chunk_id = null;
if (typeof rpcResp === 'string') chunk_id = rpcResp;
else if (rpcResp && rpcResp.id) chunk_id = rpcResp.id;
else if (Array.isArray(rpcResp) && rpcResp.length > 0 && rpcResp[0].process_transcript_chunk) chunk_id = rpcResp[0].process_transcript_chunk;
return { json: { chunk_id, accepted: chunk_id != null } };
